# Gunicorn 生产环境配置\n# 用于启动 FastAPI 应用\n\nbind = "0.0.0.0:8000"  # 监听地址\nworkers = 4             # 工作进程数（CPU核心数*2+1）\nworker_class = "uvicorn.workers.UvicornWorker"  # ASGI worker\ntimeout = 120           # 超时时间(秒)\nkeepalive = 5           # Keep-Alive 时间\nmax_requests = 1000     # 每个worker最大请求数（防止内存泄漏）\nmax_requests_jitter = 50  # 随机抖动，避免同时重启\naccesslog = "-"         # 访问日志输出到stdout\nerrorlog = "-"          # 错误日志输出到stderr\nloglevel = "info"       # 日志级别\npreload = True          # 预加载应用代码\n